# my_flask_app/app.py
from flask import Flask
from .blueprints.home import home_bp
from .blueprints.auth import auth_bp

def create_app():
    app = Flask(__name__)

    # Blueprint'leri kaydet
    app.register_blueprint(home_bp)
    app.register_blueprint(auth_bp, url_prefix='/auth') # Auth blueprint'i için /auth ön ekini kullan

    return app

if __name__ == '__main__':
    app = create_app()
    app.run(debug=True)

