from flask import Blueprint

# 'home' adında bir blueprint oluştur
home_bp = Blueprint('home', __name__)

@home_bp.route('/')
def index():
    return "Ana Sayfa - Home Blueprint"

@home_bp.route('/about')
def about():
    return "Hakkımızda Sayfası - Home Blueprint"

