from flask import Blueprint

# 'auth' adında bir blueprint oluştur
auth_bp = Blueprint('auth', __name__)

@auth_bp.route('/login')
def login():
    return "Giriş Sayfası - Auth Blueprint"

@auth_bp.route('/register')
def register():
    return "Kayıt Sayfası - Auth Blueprint"

@auth_bp.route('/logout')
def logout():
    return "Çıkış Yapıldı - Auth Blueprint"
